import React from 'react';
import './CommandeList.css';

const CommandeList = ({ commandes, onSelect, onDelete }) => {
  const handleDelete = async (idCOM) => {
    if (!window.confirm("Voulez-vous vraiment supprimer cette commande ?")) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${idCOM}`, {
        method: 'DELETE',
      });

      if (!res.ok) throw new Error(await res.text());
      onDelete(); // Recharge la liste
    } catch (err) {
      console.error('Erreur suppression commande :', err);
    }
  };

  return (
    <div>
      <h3>Liste des commandes</h3>
      <table border="1">
        <thead>
          <tr>
            <th>ID</th>
            <th>Client</th>
            <th>Article</th>
            <th>Date</th>
            <th>Quantité</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {Array.isArray(commandes) && commandes.length > 0 ? (
            commandes.map((commande) => (
              <tr key={commande.idCOM}>
                <td>{commande.idCOM}</td>
                <td>{commande.nomCli} {commande.prenomCli}</td>
                <td>{commande.nomArt}</td>
                <td>{commande.dateCom}</td>
                <td>{commande.QteCom}</td>
                <td>
                  <button onClick={() => onSelect(commande)}>Modifier</button>
                  &nbsp;
                  <button onClick={() => handleDelete(commande.idCOM)}>Supprimer</button>
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="6">Aucune commande trouvée.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default CommandeList;
